class APIService {
    
    private let secureAPIURL = "https://api.example.com/data"
    private let legacyAPIURL = "http://legacy.internal/data"
    
    func fetchFromSecureAPI(completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: secureAPIURL) else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1, userInfo: nil)))
            return
        }
        
        performRequest(url: url, completion: completion)
    }
    
    func fetchFromLegacySystem(completion: @escaping (Result<String, Error>) -> Void) {
        guard let url = URL(string: legacyAPIURL) else {
            completion(.failure(NSError(domain: "Invalid URL", code: -1, userInfo: nil)))
            return
        }
        
        performRequest(url: url, completion: completion)
    }
    
    private func performRequest(url: URL, completion: @escaping (Result<String, Error>) -> Void) {
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.timeoutInterval = 30
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(.failure(error))
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse else {
                completion(.failure(NSError(domain: "Invalid response", code: -1, userInfo: nil)))
                return
            }
            
            guard let data = data else {
                completion(.failure(NSError(domain: "No data received", code: -1, userInfo: nil)))
                return
            }
            
            let responseString = String(data: data, encoding: .utf8) ?? "Unable to parse response"
            let fullResponse = """
            Status Code: \(httpResponse.statusCode)
            URL: \(url.absoluteString)
            
            Response Data:
            \(responseString)
            """
            
            if (200...299).contains(httpResponse.statusCode) {
                completion(.success(fullResponse))
            } else {
                completion(.failure(NSError(domain: "HTTP Error", code: httpResponse.statusCode, userInfo: [NSLocalizedDescriptionKey: fullResponse])))
            }
        }
        
        task.resume()
    }
}